const body = $json.body ?? $json;
const now = new Date();
const leadName = body.name ?? body.lead_name ?? 'Unknown Lead';
const businessName = body.business_name ?? body.company ?? body.account_name ?? 'Unknown Business';
const leadEmail = body.email ?? body.lead_email ?? null;
const leadPhone = body.phone ?? body.lead_phone ?? null;
const serviceRequested = body.service ?? body.service_requested ?? 'General enquiry';
const message = body.message ?? body.lead_message ?? body.notes ?? '';
const sourceChannel = body.source_channel ?? body.lead_source ?? 'website-form';
const rawUrgency = String(body.urgency ?? 'normal').toLowerCase();
const urgency = ['low','normal','high','emergency'].includes(rawUrgency) ? rawUrgency : 'normal';
const assignedTo = body.assigned_to ?? 'ops';
const alertDestination = body.alert_destination ?? ($env.TELEGRAM_CHAT_ID || '');
const niche = body.niche ?? 'Home Services';
const requestedDate = body.booking_date ?? body.requested_date ?? body.date ?? null;
const requestedTime = body.booking_time ?? body.requested_time ?? body.time ?? null;
const bookingDurationMinutes = Number(body.booking_duration_minutes ?? body.duration_minutes ?? 60);
const bookingCalendar = body.booking_calendar ?? body.calendar_name ?? 'Work';
const requestType = String(body.inquiry_type ?? body.request_type ?? body.intent ?? '').toLowerCase();
const callNow = body.call_now === true || String(body.call_now ?? '').toLowerCase() === 'true';
const isBooking = requestType.includes('booking') || (!!requestedDate && !!requestedTime);
const isUrgentCall = requestType.includes('urgent') || requestType.includes('call') || callNow || ['urgent', 'emergency'].includes(urgency);
let inquiryType = 'standard';
if (isBooking) inquiryType = 'booking';
else if (isUrgentCall) inquiryType = 'urgent-call';
const bookingDetailsComplete = !!requestedDate && !!requestedTime;
const bookingStatus = inquiryType === 'booking' ? 'requested' : 'not-applicable';
return { json: {
  received_at: now.toISOString(),
  processed_at: now.toISOString(),
  run_id: `run_${Date.now()}`,
  lead_name: leadName,
  business_name: businessName,
  lead_email: leadEmail,
  lead_phone: leadPhone,
  service_requested: serviceRequested,
  message,
  source_channel: sourceChannel,
  urgency,
  assigned_to: assignedTo,
  alert_destination: alertDestination,
  niche,
  inquiry_type: inquiryType,
  requested_booking_date: requestedDate,
  requested_booking_time: requestedTime,
  booking_status: bookingStatus,
  booking_calendar: bookingCalendar,
  booking_duration_minutes: Number.isFinite(bookingDurationMinutes) ? bookingDurationMinutes : 60,
  booking_details_complete: bookingDetailsComplete
} };

const lead = $node['Normalize + Route Lead'].json;
const customerRes = $node['Upsert Customer'].json;
const customerId = customerRes?.[0]?.id || customerRes?.id || null;
const submissionRes = $node['Insert Lead Submission'].json;
const submissionId = submissionRes?.[0]?.id || submissionRes?.id || null;
const bookingDate = lead.requested_booking_date || 'TBD';
const bookingTime = lead.requested_booking_time || 'TBD';
let title = `Follow up: ${lead.business_name}`;
let description = `New inbound lead for ${lead.service_requested}. ${lead.message || ''}`.trim();
let priority = lead.urgency === 'emergency' ? 'urgent' : (lead.urgency === 'high' ? 'high' : 'medium');
let bookingNeedsConfirmation = false;
let summary = `Lead captured for ${lead.business_name}`;
if (lead.inquiry_type === 'booking') {
  title = `Booking: ${lead.business_name}`;
  description = `Booking request for ${lead.service_requested}. Requested date: ${bookingDate}. Requested time: ${bookingTime}. ${lead.message || ''}`.trim();
  priority = 'high';
  bookingNeedsConfirmation = !lead.booking_details_complete;
  summary = bookingNeedsConfirmation ? `Booking request captured for ${lead.business_name} - missing booking details.` : `Booking request captured for ${lead.business_name}`;
}
if (lead.inquiry_type === 'urgent-call') {
  title = `Urgent call: ${lead.business_name}`;
  description = `Urgent callback needed for ${lead.service_requested}. ${lead.message || ''}`.trim();
  priority = 'urgent';
  summary = `Urgent call request captured for ${lead.business_name}`;
}
const dueDate = lead.inquiry_type === 'booking' && lead.requested_booking_date ? lead.requested_booking_date : null;
const calendarPayload = lead.inquiry_type === 'booking' ? {
  summary: `${lead.business_name} booking - ${lead.lead_name}`,
  calendar: lead.booking_calendar || 'Work',
  description: `Lead booking from G7CRM / n8n\nService: ${lead.service_requested}\nLead: ${lead.lead_name}\nEmail: ${lead.lead_email || '—'}\nPhone: ${lead.lead_phone || '—'}\nMessage: ${lead.message || '—'}\nRun ID: ${lead.run_id}`,
  iso_date: lead.requested_booking_date || null,
  hour: lead.requested_booking_time ? Number(String(lead.requested_booking_time).split(':')[0]) : null,
  minute: lead.requested_booking_time ? Number(String(lead.requested_booking_time).split(':')[1] || 0) : 0,
  duration_minutes: lead.booking_duration_minutes || 60,
  alarm_minutes: 30,
  booking_needs_confirmation: bookingNeedsConfirmation
} : null;
const telegramMessage = lead.inquiry_type === 'urgent-call'
  ? `Urgent call request\n\nBusiness: ${lead.business_name}\nLead: ${lead.lead_name}\nPhone: ${lead.lead_phone || '—'}\nService: ${lead.service_requested}\nUrgency: ${lead.urgency}\nMessage: ${lead.message || '—'}\nRun ID: ${lead.run_id}`
  : (lead.inquiry_type === 'booking'
    ? `Booking request\n\nBusiness: ${lead.business_name}\nLead: ${lead.lead_name}\nRequested date: ${bookingDate}\nRequested time: ${bookingTime}\nService: ${lead.service_requested}\nNeeds confirmation: ${bookingNeedsConfirmation ? 'yes' : 'no'}\nRun ID: ${lead.run_id}`
    : `New inbound lead\n\nBusiness: ${lead.business_name}\nLead: ${lead.lead_name}\nService: ${lead.service_requested}\nUrgency: ${lead.urgency}\nRun ID: ${lead.run_id}`);
return { json: { ...lead, customer_id: customerId, lead_submission_id: submissionId, task_title: title, task_description: description, task_priority: priority, task_due_date: dueDate, booking_needs_confirmation: bookingNeedsConfirmation, calendar_payload: calendarPayload, routing_summary: summary, telegram_message: telegramMessage } };
